import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"What is Sovereign?","description":"Learn how Sovereign brings private, multi-user apps together in a workspace you control.","frontmatter":{"title":"What is Sovereign?","description":"Learn how Sovereign brings private, multi-user apps together in a workspace you control.","aside":false},"headers":[],"relativePath":"product/index.md","filePath":"product/index.md"}'),n={name:"product/index.md"};function i(s,e,l,h,p,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="an-open-source-workspace-runtime" tabindex="-1">An open-source workspace runtime <a class="header-anchor" href="#an-open-source-workspace-runtime" aria-label="Permalink to &quot;An open-source workspace runtime&quot;">​</a></h1><p>Sovereign hosts private, multi-user apps on infrastructure you control. An operator runs one Sovereign instance, invites the people who should use it, and chooses which apps are available in their shared workspace.</p><p>That is useful in two ways. A group can install apps that already meet its needs, or a developer can build a purpose-specific app without rebuilding the platform underneath it.</p><h2 id="the-product-model" tabindex="-1">The product model <a class="header-anchor" href="#the-product-model" aria-label="Permalink to &quot;The product model&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Part</th><th>What it means</th></tr></thead><tbody><tr><td><strong>Instance</strong></td><td>One deployed Sovereign installation.</td></tr><tr><td><strong>Operator</strong></td><td>The person or organization responsible for infrastructure, policy, and apps.</td></tr><tr><td><strong>Workspace</strong></td><td>The environment users enter after signing in.</td></tr><tr><td><strong>App</strong></td><td>A user-facing capability available in the workspace.</td></tr><tr><td><strong>Plugin</strong></td><td>The technical package and contract used to deliver an app to Sovereign.</td></tr></tbody></table><h2 id="what-sovereign-handles" tabindex="-1">What Sovereign handles <a class="header-anchor" href="#what-sovereign-handles" aria-label="Permalink to &quot;What Sovereign handles&quot;">​</a></h2><p>Sovereign provides a common shell and reusable platform foundations for authentication, user sessions, app-scoped data, interface components, access control, and other platform services. An app developer can concentrate on a workflow rather than operating a separate authentication service, database integration, and application shell for every tool.</p><p>Platform capabilities have different maturity levels. The <a href="./features.html">features</a> page distinguishes what is available from what is still being developed or explored.</p><h2 id="what-the-operator-controls" tabindex="-1">What the operator controls <a class="header-anchor" href="#what-the-operator-controls" aria-label="Permalink to &quot;What the operator controls&quot;">​</a></h2><p>Self-hosting makes the operator responsible. The operator chooses where the instance runs, who can join, which apps are enabled, how backups work, when upgrades happen, and which policies apply. Users should understand and trust their operator before placing data in an instance.</p><h2 id="what-sovereign-is-not" tabindex="-1">What Sovereign is not <a class="header-anchor" href="#what-sovereign-is-not" aria-label="Permalink to &quot;What Sovereign is not&quot;">​</a></h2><ul><li>It is not a hosted service operated centrally by the Sovereign project.</li><li>It is not a fixed suite of apps; operators can choose and developers can extend the workspace.</li><li>It is not peer-to-peer by default; a standard Sovereign instance is operated infrastructure.</li><li>It does not remove operational responsibility or eliminate the need to trust the chosen operator.</li></ul><h2 id="continue-exploring" tabindex="-1">Continue exploring <a class="header-anchor" href="#continue-exploring" aria-label="Permalink to &quot;Continue exploring&quot;">​</a></h2><ul><li><a href="./why-sovereign.html">Why Sovereign exists</a></li><li><a href="./how-it-works.html">How an instance works</a></li><li><a href="./features.html">Review features and their status</a></li><li><a href="./apps.html">See apps</a></li><li><a href="/get-started/">Choose a getting-started path</a></li></ul>',14)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
